import { Toolbar as ToolbarPrimitive } from '@base-ui/react/toolbar';
import { forwardRef, type ComponentRef } from 'react';
import { mergeClassName } from '@/lib/moduix/mergeClassName';
import styles from './Toolbar.module.css';

const Toolbar = forwardRef<ComponentRef<typeof ToolbarPrimitive.Root>, ToolbarPrimitive.Root.Props>(
  function Toolbar({ className, ...props }, ref) {
    return (
      <ToolbarPrimitive.Root
        ref={ref}
        data-slot="toolbar-root"
        className={mergeClassName(className, styles.root)}
        {...props}
      />
    );
  },
);

const ToolbarGroup = forwardRef<
  ComponentRef<typeof ToolbarPrimitive.Group>,
  ToolbarPrimitive.Group.Props
>(function ToolbarGroup({ className, ...props }, ref) {
  return (
    <ToolbarPrimitive.Group
      ref={ref}
      data-slot="toolbar-group"
      className={mergeClassName(className, styles.group)}
      {...props}
    />
  );
});

const ToolbarButton = forwardRef<
  ComponentRef<typeof ToolbarPrimitive.Button>,
  ToolbarPrimitive.Button.Props
>(function ToolbarButton({ className, ...props }, ref) {
  return (
    <ToolbarPrimitive.Button
      ref={ref}
      data-slot="toolbar-button"
      className={mergeClassName(className, styles.button)}
      {...props}
    />
  );
});

const ToolbarLink = forwardRef<
  ComponentRef<typeof ToolbarPrimitive.Link>,
  ToolbarPrimitive.Link.Props
>(function ToolbarLink({ className, ...props }, ref) {
  return (
    <ToolbarPrimitive.Link
      ref={ref}
      data-slot="toolbar-link"
      className={mergeClassName(className, styles.link)}
      {...props}
    />
  );
});

const ToolbarInput = forwardRef<
  ComponentRef<typeof ToolbarPrimitive.Input>,
  ToolbarPrimitive.Input.Props
>(function ToolbarInput({ className, ...props }, ref) {
  return (
    <ToolbarPrimitive.Input
      ref={ref}
      data-slot="toolbar-input"
      className={mergeClassName(className, styles.input)}
      {...props}
    />
  );
});

const ToolbarSeparator = forwardRef<
  ComponentRef<typeof ToolbarPrimitive.Separator>,
  ToolbarPrimitive.Separator.Props
>(function ToolbarSeparator({ className, ...props }, ref) {
  return (
    <ToolbarPrimitive.Separator
      ref={ref}
      data-slot="toolbar-separator"
      className={mergeClassName(className, styles.separator)}
      {...props}
    />
  );
});

export { Toolbar, ToolbarGroup, ToolbarButton, ToolbarLink, ToolbarInput, ToolbarSeparator };

@layer ui.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    gap: var(--toolbar-gap, var(--border-width-sm));
    padding: var(--toolbar-padding, 0.125rem);
    border: var(--toolbar-border-width, var(--border-width-sm)) solid
      var(--toolbar-border-color, var(--color-border));
    border-radius: var(--toolbar-radius, var(--radius-lg));
    background-color: var(--toolbar-bg, var(--color-muted));
    color: var(--toolbar-color, var(--color-foreground));

    &[data-orientation='vertical'] {
      flex-direction: column;
      align-items: stretch;
    }
  }

  .group {
    display: inline-flex;
    align-items: center;
    gap: var(--toolbar-group-gap, var(--spacing-1));

    &[data-orientation='vertical'] {
      flex-direction: column;
      align-items: stretch;
    }
  }

  .button {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--toolbar-control-gap, var(--spacing-2));
    min-width: var(--toolbar-control-height, var(--size-lg));
    min-height: var(--toolbar-control-height, var(--size-lg));
    margin: 0;
    border: var(--toolbar-control-border-width, var(--border-width-sm)) solid transparent;
    border-radius: var(--toolbar-control-radius, var(--radius-md));
    padding-block: 0;
    padding-inline: var(--toolbar-control-padding-x, 0.75rem);
    background-color: transparent;
    color: var(--toolbar-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--toolbar-font-size, var(--text-sm));
    font-weight: var(--toolbar-font-weight, var(--weight-medium));
    line-height: var(--toolbar-line-height, var(--line-height-text-sm));
    text-decoration: none;
    user-select: none;
    white-space: nowrap;
    cursor: pointer;
    transition:
      background-color var(--toolbar-transition, var(--transition-default)),
      border-color var(--toolbar-transition, var(--transition-default)),
      color var(--toolbar-transition, var(--transition-default)),
      opacity var(--toolbar-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--toolbar-control-bg-hover, var(--color-accent));
      }
    }

    &:active {
      background-color: var(--toolbar-control-bg-active, var(--color-accent));
    }

    &:focus-visible {
      outline: var(--toolbar-focus-ring-width, var(--border-width-md)) solid
        var(--toolbar-focus-ring-color, var(--color-ring));
      outline-offset: var(--toolbar-focus-ring-offset, -1px);
    }

    &[data-disabled],
    &[disabled] {
      opacity: var(--toolbar-disabled-opacity, var(--opacity-disabled));
      cursor: default;
      pointer-events: none;
    }

    &[data-pressed],
    &[data-popup-open] {
      border-color: var(--toolbar-control-border-color-active, transparent);
      background-color: var(--toolbar-control-bg-pressed, var(--color-background));
      color: var(--toolbar-control-color-pressed, var(--color-foreground));
    }

    :where(svg) {
      width: var(--toolbar-icon-size, 1rem);
      height: var(--toolbar-icon-size, 1rem);
      flex-shrink: 0;
    }

    &:empty,
    &:has(> svg:only-child) {
      width: var(--toolbar-control-height, var(--size-lg));
      padding-inline: 0;
    }

    .root[data-orientation='vertical'] & {
      width: 100%;
    }
  }

  .link {
    flex: 0 0 auto;
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    min-height: var(--toolbar-control-height, var(--size-lg));
    border-radius: var(--toolbar-control-radius, var(--radius-md));
    padding-inline: var(--toolbar-control-padding-x, 0.75rem);
    color: var(--toolbar-control-color, var(--color-foreground));
    font: inherit;
    font-size: var(--toolbar-font-size, var(--text-sm));
    font-weight: var(--toolbar-font-weight, var(--weight-medium));
    line-height: var(--toolbar-line-height, var(--line-height-text-sm));
    text-decoration: none;
    white-space: nowrap;
    transition:
      background-color var(--toolbar-transition, var(--transition-default)),
      color var(--toolbar-transition, var(--transition-default)),
      opacity var(--toolbar-transition, var(--transition-default));

    @media (hover: hover) {
      &:hover {
        background-color: var(--toolbar-control-bg-hover, var(--color-accent));
      }
    }

    &:active {
      background-color: var(--toolbar-control-bg-active, var(--color-accent));
    }

    &:focus-visible {
      outline: var(--toolbar-focus-ring-width, var(--border-width-md)) solid
        var(--toolbar-focus-ring-color, var(--color-ring));
      outline-offset: var(--toolbar-focus-ring-offset, -1px);
    }

    &[data-disabled],
    &[disabled] {
      opacity: var(--toolbar-disabled-opacity, var(--opacity-disabled));
      cursor: default;
      pointer-events: none;
    }
  }

  .input {
    box-sizing: border-box;
    width: var(--toolbar-input-width, 10rem);
    min-width: 0;
    height: var(--toolbar-control-height, var(--size-lg));
    margin: 0;
    border: var(--toolbar-input-border-width, var(--border-width-sm)) solid
      var(--toolbar-input-border-color, var(--color-border));
    border-radius: var(--toolbar-control-radius, var(--radius-md));
    padding-block: 0;
    padding-inline: var(--toolbar-input-padding-x, 0.75rem);
    background-color: var(--toolbar-input-bg, var(--color-background));
    color: var(--toolbar-input-color, var(--color-foreground));
    font: inherit;
    font-size: var(--toolbar-font-size, var(--text-sm));
    line-height: var(--toolbar-line-height, var(--line-height-text-sm));
    outline: var(--toolbar-focus-ring-width, var(--border-width-md)) solid transparent;
    outline-offset: var(--toolbar-focus-ring-offset, -1px);
    transition:
      border-color var(--toolbar-transition, var(--transition-default)),
      outline-color var(--toolbar-transition, var(--transition-default)),
      opacity var(--toolbar-transition, var(--transition-default));

    &::placeholder {
      color: var(--toolbar-input-placeholder-color, var(--color-muted-foreground));
    }

    &:focus-visible {
      outline-color: var(--toolbar-focus-ring-color, var(--color-ring));
    }

    .root[data-orientation='vertical'] & {
      width: 100%;
    }

    &[data-disabled],
    &[disabled] {
      opacity: var(--toolbar-disabled-opacity, var(--opacity-disabled));
      cursor: default;
    }
  }

  .separator {
    flex-shrink: 0;
    align-self: center;
    margin: 0;
    background-color: var(--toolbar-separator-color, var(--color-border));

    &[data-orientation='horizontal'] {
      width: var(--toolbar-separator-length-horizontal, 100%);
      height: var(--toolbar-separator-thickness, 1px);
      margin-block: var(--toolbar-separator-margin-y-horizontal, var(--spacing-1));
    }

    &[data-orientation='vertical'] {
      width: var(--toolbar-separator-thickness, 1px);
      height: var(--toolbar-separator-length-vertical, 1rem);
      margin-inline: var(--toolbar-separator-margin-x-vertical, var(--spacing-1));
    }
  }
}

export {
  Toolbar,
  ToolbarGroup,
  ToolbarButton,
  ToolbarLink,
  ToolbarInput,
  ToolbarSeparator,
} from './Toolbar';
